131	    /**
132	     * GET /api/v1/agents/permissions/:id
133	     *
134	     * Returns the integration permission catalog plus the currently granted
135	     * action keys for the agent. The frontend renders the catalog as a
136	     * checklist and uses `granted` to pre-tick the rows the admin has
137	     * already authorised.
138	     *
139	     * Response shape:
140	     *   {
141	     *     "agent": { "id": int, "name": string },
142	     *     "catalog": { "<integration>": [{ "action": string, "label": string }, ...] },
143	     *     "granted": ["<action>", ...]
144	     *   }
145	     */
146	    public function permissions(int $id): void
147	    {
148	        $this->requirePermission('agents', 'read');
149	        $agent = $this->agentService->findById($id);
150	
151	        if ($agent === null) {
152	            $this->error('Agent not found', [], 404);
153	            return;
154	        }
155	
156	        $permissionSet = $this->permissionService->loadForAgent($id);
157	
158	        $this->success([
159	            'agent' => ['id' => $agent->id, 'name' => $agent->name],
160	            'catalog' => $this->permissionService->getCatalog(),
161	            'granted' => $permissionSet->all(),
162	        ]);
163	    }
164	
165	    /**
166	     * POST /api/v1/agents/update-permissions/:id
167	     *
168	     * Body: { actions: ["github.issues.read", ...] }
169	     *
170	     * Replaces the agent's permission set with the supplied list of action
171	     * keys. Unknown keys are silently dropped (see
172	     * AgentIntegrationPermissionService::replaceForAgent). Writes an
173	     * audit-log row describing the diff between previous and new grants so
174	     * operators can review who changed what — required by the issue's
175	     * "log changes to permissions" acceptance criterion.
176	     */
177	    public function updatePermissions(int $id): void
178	    {
179	        $this->requirePermission('agents', 'update');
180	        $agent = $this->agentService->findById($id);
181	
182	        if ($agent === null) {
183	            $this->error('Agent not found', [], 404);
184	            return;
185	        }
186	
187	        $raw = $this->request->getData('actions');
188	        if (!is_array($raw)) {
189	            $this->error('actions must be an array of action keys', [], 422);
190	            return;
191	        }
192	
193	        $requested = [];
194	        foreach ($raw as $action) {
195	            if (is_string($action) && $action !== '') {
196	                $requested[] = $action;
197	            }
198	        }
199	
200	        $previous = $this->permissionService->loadForAgent($id)->all();
201	        $this->permissionService->replaceForAgent($id, $requested);
202	        $current = $this->permissionService->loadForAgent($id)->all();
203	
204	        $added = array_values(array_diff($current, $previous));
205	        $removed = array_values(array_diff($previous, $current));
206	
207	        $user = $this->getCurrentUser();
208	        $this->logService->log(
209	            agentId: $id,
210	            executionId: Uuid::uuid4()->toString(),
211	            level: 'info',
212	            message: sprintf(
213	                'Integration permissions updated for agent #%d: +%d / -%d',
214	                $id,
215	                count($added),
216	                count($removed),
217	            ),
218	            context: ['added' => $added, 'removed' => $removed, 'final' => $current],
219	            userId: $user?->id,
220	            resultState: 'success',
221	        );
222	
223	        $this->success([
224	            'agent' => ['id' => $agent->id, 'name' => $agent->name],
225	            'granted' => $current,
226	            'diff' => ['added' => $added, 'removed' => $removed],
227	        ]);
228	    }
229	}
