    /**
     * Filters the supplied list of tool definitions down to the ones the
     * agent has been granted permission to call. Tools that are not gated
     * (action map returns null) are passed through unchanged.
     *
     * @param ToolDefinition[] $tools
     * @return ToolDefinition[]
     */
    private function filterToolsByPermission(array $tools): array
    {
        $allowed = [];
        foreach ($tools as $tool) {
            $required = $this->permissions->getActionForTool($tool->name);
            if ($required === null || $this->permissionSet->has($required)) {
                $allowed[] = $tool;
            }
        }

        return $allowed;
    }

    /**
     * Throws PermissionDeniedException when the agent does not have the
     * action required to call the named tool. Tools that are not gated
     * (no entry in the action map) are allowed unconditionally.
     */
    private function assertToolAllowed(string $toolName): void
    {
        $required = $this->permissions->getActionForTool($toolName);
        if ($required === null) {
            return;
        }
        if (!$this->permissionSet->has($required)) {
            throw new PermissionDeniedException($toolName, $required);
        }
    }

    /**
     * Writes an audit-log entry for a denied tool invocation so operators
     * can see every attempt the agent made to exceed its grant set. Falls
     * back to the framework log when no AgentLogService is wired.
     */
    private function logPermissionDenial(PermissionDeniedException $e): void
    {
        $this->log(
            "AgentLoop permission denied: tool={$e->tool} action={$e->requiredAction}",
            'warning',
            ['scope' => 'agent_loop_permission_denied'],
        );

        if ($this->logService === null || $this->agentId === null || $this->executionId === null) {
            return;
        }

        $this->logService->log(
            agentId: $this->agentId,
            executionId: $this->executionId,
            level: 'warning',
            message: sprintf(
                'Permission denied for tool "%s" — required action "%s" was not granted.',
                $e->tool,
                $e->requiredAction,
            ),
            context: ['tool' => $e->tool, 'required_action' => $e->requiredAction],
            userId: $this->userId,
            resultState: 'denied',
            errorMessage: $e->getMessage(),
        );
    }
}

