179	    public function testRunSurfacesPermissionDeniedAsToolErrorWithoutCrashing(): void
180	    {
181	        // First the LLM requests a write tool the agent has not been granted;
182	        // the provider throws PermissionDeniedException, the loop catches it
183	        // and feeds back a TOOL_ERROR result that the LLM uses to compose the
184	        // final user-facing answer in the second iteration.
185	        $toolCallResponse = new ToolCallResponse(
186	            content: '',
187	            toolCalls: [new ToolCall(id: 'call_1', name: 'github_create_issue', arguments: [])],
188	            model: 'gpt-4o',
189	            tokensUsed: 5,
190	        );
191	        $finalResponse = new ToolCallResponse(
192	            content: "I don't have permission to create issues.",
193	            toolCalls: [],
194	            model: 'gpt-4o',
195	            tokensUsed: 10,
196	        );
197	
198	        $this->toolProvider->method('getDefinitions')->willReturn([]);
199	        $this->toolProvider->method('dispatch')
200	            ->willThrowException(new PermissionDeniedException('github_create_issue', 'github.issues.write'));
201	        $this->client->method('completeWithTools')
202	            ->willReturnOnConsecutiveCalls($toolCallResponse, $finalResponse);
203	
204	        $events = [];
205	        $result = $this->service->run($this->makeMessages(), [], function (string $e) use (&$events) {
206	            $events[] = json_decode($e, true);
207	        });
208	
209	        $this->assertSame("I don't have permission to create issues.", $result->content);
210	        $hasToolResult = false;
211	        foreach ($events as $event) {
212	            if (($event['type'] ?? '') === 'tool_result'
213	                && str_contains((string)($event['result'] ?? ''), 'TOOL_ERROR')
214	                && str_contains((string)($event['result'] ?? ''), 'github.issues.write')
215	            ) {
216	                $hasToolResult = true;
217	                break;
218	            }
219	        }
220	        $this->assertTrue($hasToolResult, 'PermissionDenied should be emitted as a TOOL_ERROR tool_result event.');
221	    }
