    // ── Permission filtering (issue #9) ───────────────────────────────────────

    public function testGetDefinitionsFiltersByGrantedActionsWhenPermissionSetSupplied(): void
    {
        // Agent has only the read-side issue grant — write tools and unrelated
        // categories must be omitted from the LLM's tool catalog so the model
        // cannot even ask for them.
        $permissions = new AgentPermissionSet(['github.issues.read']);
        $provider = new GitHubToolProvider($this->github, $permissions);

        $names = array_map(fn($d) => $d->name, $provider->getDefinitions());
