        );
    }

    public function testGetDefinitionsReturnsAllToolsWhenNoPermissionSetSupplied(): void
    {
        // Backwards-compatibility path: legacy call sites construct the
        // provider without injecting a permission set and continue to see
        // every tool.
        $provider = new GitHubToolProvider($this->github);
        $this->assertCount(14, $provider->getDefinitions());
    }

    public function testDispatchThrowsPermissionDeniedWhenActionNotGranted(): void
    {
        $permissions = new AgentPermissionSet(['github.issues.read']);
        $provider = new GitHubToolProvider($this->github, $permissions);

        $this->github->expects($this->never())->method('createIssue');

        try {
            $provider->dispatch('github_create_issue', [
                'owner' => 'acme',
                'repo' => 'app',
                'title' => 'Should be blocked',
            ]);
            $this->fail('Expected PermissionDeniedException');
        } catch (PermissionDeniedException $e) {
            $this->assertSame('github_create_issue', $e->tool);
            $this->assertSame('github.issues.write', $e->requiredAction);
        }
    }

    public function testDispatchAllowsCallWhenActionIsGranted(): void
    {
        $permissions = new AgentPermissionSet(['github.issues.read']);
        $provider = new GitHubToolProvider($this->github, $permissions);

        $this->github->expects($this->once())
            ->method('listIssues')
            ->willReturn([
                ['number' => 1, 'state' => 'open', 'title' => 'first', 'html_url' => 'https://x/1'],
            ]);

        $result = $provider->dispatch('github_list_issues', [
            'owner' => 'acme',
            'repo' => 'app',
        ]);

        $this->assertStringContainsString('#1', $result);
    }
}

